while True:
    namn = input("Skriv ett namn (eller 'a' för att avsluta): ")
    if namn == 'a':
        print("Programmet avslutas.")
        break  # Avslutar loopen

    if namn == "":
        print("Du skrev inget namn. Försök igen.")
        continue  # Hoppar över resten och börjar om

    if namn == "Malin":
        print("Hej Malin! Trevligt att se dig igen.")

    elif namn == "Erik":
        print("Tjena Erik! Det var länge sedan.")

    else:
        print("Hej "+ namn + "!")


antal_namn = int(input("Hur många fler namn vill du mata in?"))
inmatade = 0
while inmatade < antal_namn:
    namn = input("Skriv ett namn: ")

    if namn == "":
        print("Du skrev inget namn. Försök igen.")
        continue  # Hoppar över resten och börjar om

    else:
        print("Hej "+ namn + "!")
        inmatade +=1 #lägger till ett till inmatade, nu har vi matat in ett namn

print("Programmet avslutas, du har matat in", antal_namn,"namn till.")
